    if len(parts) == 0:
        return ""
    elif len(parts) == 1:
        sentence = parts[0]
    elif len(parts) == 2:
        sentence = parts[0] + ", and " + parts[1]
    else:
        # Join with commas and use 'and' before the last item for better flow
        sentence = ", ".join(parts[:-1]) + ", and " + parts[-1]

    # Ensure the first character is capitalised and ends with period
    sentence = sentence[0].upper() + sentence[1:]
    if not sentence.endswith('.'):
        sentence += '.'
